-- Table for breeders\nCREATE TABLE breeders (\n    id SERIAL PRIMARY KEY,\n    name VARCHAR(100) NOT NULL,\n    contact_info VARCHAR(255) NOT NULL\n);\n\n-- Table for cockatiels\nCREATE TABLE cockatiels (\n    id SERIAL PRIMARY KEY,\n    name VARCHAR(100) NOT NULL,\n    breed VARCHAR(100) NOT NULL,\n    age INT NOT NULL,\n    breeder_id INT REFERENCES breeders(id)\n);\n\n-- Table for breeding pairs\nCREATE TABLE breeding_pairs (\n    id SERIAL PRIMARY KEY,\n    cockatiel_1_id INT REFERENCES cockatiels(id),\n    cockatiel_2_id INT REFERENCES cockatiels(id)\n);\n\n-- Table for clutches\nCREATE TABLE clutches (\n    id SERIAL PRIMARY KEY,\n    breeding_pair_id INT REFERENCES breeding_pairs(id),\n    date_laid DATE NOT NULL,\n    total_eggs INT NOT NULL\n);\n\n-- Table for health records\nCREATE TABLE health_records (\n    id SERIAL PRIMARY KEY,\n    cockatiel_id INT REFERENCES cockatiels(id),\n    health_issue VARCHAR(255),\n    treatment VARCHAR(255),\n    date_recorded DATE NOT NULL\n);\n\n-- Table for sales\nCREATE TABLE sales (\n    id SERIAL PRIMARY KEY,\n    cockatiel_id INT REFERENCES cockatiels(id),\n    date_sold DATE NOT NULL,\n    buyer_info VARCHAR(255) NOT NULL,\n    sale_price DECIMAL(10, 2) NOT NULL\n);\n